import{_ as a,o as t,c as n,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Baserunning Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/baserunning.md","filePath":"analytics/baserunning.md"}'),r={name:"analytics/baserunning.md"};function i(o,e,c,h,d,l){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="baserunning-analytics" tabindex="-1">Baserunning Analytics <a class="header-anchor" href="#baserunning-analytics" aria-label="Permalink to &quot;Baserunning Analytics&quot;">​</a></h1><h2 id="key-stats" tabindex="-1">Key Stats <a class="header-anchor" href="#key-stats" aria-label="Permalink to &quot;Key Stats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stat</th><th>Description</th></tr></thead><tbody><tr><td>SB</td><td>Stolen bases — total successful steals</td></tr><tr><td>CS</td><td>Caught stealing — total times thrown out</td></tr><tr><td>SB%</td><td>Stolen base percentage — SB ÷ (SB + CS)</td></tr><tr><td>PO</td><td>Pickoffs — times picked off a base</td></tr></tbody></table><h2 id="stolen-base-percentage" tabindex="-1">Stolen Base Percentage <a class="header-anchor" href="#stolen-base-percentage" aria-label="Permalink to &quot;Stolen Base Percentage&quot;">​</a></h2><p>SB% is the primary baserunning metric. A rate above 70% is generally considered acceptable at the youth level — below that the stolen base attempts may be hurting more than helping.</p><h2 id="per-base-breakdown" tabindex="-1">Per-Base Breakdown <a class="header-anchor" href="#per-base-breakdown" aria-label="Permalink to &quot;Per-Base Breakdown&quot;">​</a></h2><p>The per-base breakdown shows separate stats for attempts at second, third, and home. This reveals where a runner&#39;s aggressiveness or caution is most affecting performance.</p><p>A player who steals second at 90% but gets caught stealing third at 50% needs to be more selective about when to attempt third.</p><h2 id="trend-chart" tabindex="-1">Trend Chart <a class="header-anchor" href="#trend-chart" aria-label="Permalink to &quot;Trend Chart&quot;">​</a></h2><p>The trend chart shows SB% over time across the season. Use this to evaluate whether baserunning decision-making is improving.</p><h2 id="connection-to-baserunning-mechanics" tabindex="-1">Connection to Baserunning Mechanics <a class="header-anchor" href="#connection-to-baserunning-mechanics" aria-label="Permalink to &quot;Connection to Baserunning Mechanics&quot;">​</a></h2><p>Players with low SB% or high pickoff rates may benefit from a Baserunning Mechanics assessment to evaluate lead, secondary lead and read, and running form. See <a href="/analytics/mechanics.html">Mechanics Assessments</a> for details.</p>',12)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
